
      CREATE   VIEW dbo.projpostedtransinvoicestatus AS 
      SELECT [projpostedtransinvoicestatus].[Id] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [Id],[projpostedtransinvoicestatus].[SinkCreatedOn] AS [SinkCreatedOn],[projpostedtransinvoicestatus].[SinkModifiedOn] AS [SinkModifiedOn],[projpostedtransinvoicestatus].[projinvoicestatus] AS [projinvoicestatus],[projpostedtransinvoicestatus].[hasadjusted] AS [hasadjusted],[projpostedtransinvoicestatus].[haschargeable] AS [haschargeable],[projpostedtransinvoicestatus].[hasfullyinvoiced] AS [hasfullyinvoiced],[projpostedtransinvoicestatus].[hasfullyinvoicedwithonhold] AS [hasfullyinvoicedwithonhold],[projpostedtransinvoicestatus].[sysdatastatecode] AS [sysdatastatecode],[projpostedtransinvoicestatus].[sessionid] AS [sessionid],[projpostedtransinvoicestatus].[sessionlogindatetime] AS [sessionlogindatetime],[projpostedtransinvoicestatus].[postedtransrefrecid] AS [postedtransrefrecid],[projpostedtransinvoicestatus].[voucher_custom] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [voucher_custom],[projpostedtransinvoicestatus].[modifieddatetime] AS [modifieddatetime],[projpostedtransinvoicestatus].[modifiedby] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [modifiedby],[projpostedtransinvoicestatus].[modifiedtransactionid] AS [modifiedtransactionid],[projpostedtransinvoicestatus].[createddatetime] AS [createddatetime],[projpostedtransinvoicestatus].[createdby] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [createdby],[projpostedtransinvoicestatus].[createdtransactionid] AS [createdtransactionid],[projpostedtransinvoicestatus].[dataareaid] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [dataareaid],[projpostedtransinvoicestatus].[recversion] AS [recversion],[projpostedtransinvoicestatus].[partition] AS [partition],[projpostedtransinvoicestatus].[sysrowversion] AS [sysrowversion],[projpostedtransinvoicestatus].[recid] AS [recid],[projpostedtransinvoicestatus].[tableid] AS [tableid],[projpostedtransinvoicestatus].[versionnumber] AS [versionnumber],[projpostedtransinvoicestatus].[createdon] AS [createdon],[projpostedtransinvoicestatus].[modifiedon] AS [modifiedon],[projpostedtransinvoicestatus].[IsDelete] AS [IsDelete],[projpostedtransinvoicestatus].[PartitionId] COLLATE Latin1_General_100_CI_AS_KS_WS_SC_UTF8 AS [PartitionId],CASE [projpostedtransinvoicestatus].[hasadjusted] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS hasadjusted_$label,CASE [projpostedtransinvoicestatus].[haschargeable] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS haschargeable_$label,CASE [projpostedtransinvoicestatus].[hasfullyinvoiced] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS hasfullyinvoiced_$label,CASE [projpostedtransinvoicestatus].[hasfullyinvoicedwithonhold] WHEN 0 THEN 'No'  WHEN 1 THEN 'Yes'  END AS hasfullyinvoicedwithonhold_$label,CASE [projpostedtransinvoicestatus].[projinvoicestatus] WHEN 0 THEN 'None'  WHEN 1 THEN 'PartiallyInvoiced'  WHEN 2 THEN 'FullyInvoiced'  WHEN 3 THEN 'Chargeable'  WHEN 4 THEN 'Nonchargeable'  WHEN 5 THEN 'PartiallyInvoicedWithOnhold'  WHEN 6 THEN 'FullyInvoicedWithOnhold'  WHEN 7 THEN 'Adjusted'  END AS projinvoicestatus_$label
      FROM dataverse_stiprod_cds2_workspace_unqce8cf9ab47aff01187066045bdff8.dbo.projpostedtransinvoicestatus WHERE projpostedtransinvoicestatus.IsDelete IS NULL

